1	constant float dsv4_e4m3fn_exp_scale[16] = {
2	    0.0f, 0.015625f, 0.03125f, 0.0625f,
3	    0.125f, 0.25f, 0.5f, 1.0f,
4	    2.0f, 4.0f, 8.0f, 16.0f,
5	    32.0f, 64.0f, 128.0f, 256.0f,
6	};
7	
8	constant float dsv4_e2m1fn_values[8] = {
9	    0.0f, 0.5f, 1.0f, 1.5f, 2.0f, 3.0f, 4.0f, 6.0f,
10	};
11	
12	struct ds4_metal_args_dsv4_fp8_kv_quantize {
13	    int64_t ne00;
14	    int64_t ne01;
15	    int64_t ne02;
16	    int64_t ne03;
17	    ulong nb00;
18	    ulong nb01;
19	    ulong nb02;
20	    ulong nb03;
21	    ulong nb0;
22	    ulong nb1;
23	    ulong nb2;
24	    ulong nb3;
25	    int n_rot;
26	};
27	
28	struct ds4_metal_args_dsv4_kv_fp8_store {
29	    int32_t head_dim;
30	    int32_t n_rot;
31	    int32_t raw_row;
32	};
33	
34	struct ds4_metal_args_dsv4_indexer_qat {
35	    uint32_t n_rows;
36	    uint32_t head_dim;
37	    uint64_t row_stride;
38	};
39	
40	struct ds4_metal_args_dsv4_ratio4_shift {
41	    uint32_t width;
42	};
43	
44	struct ds4_metal_args_dsv4_compressor_store_one {
45	    uint32_t width;
46	    uint32_t ratio;
47	    uint32_t pos;
48	    uint32_t ape_type;
49	};
50	
51	static inline float dsv4_e4m3fn_value(int i) {
52	    const int exp  = (i >> 3) & 0x0f;
53	    const int mant = i & 0x07;
54	    return exp == 0
55	        ? float(mant) * 0.001953125f
56	        : (1.0f + float(mant) * 0.125f) * dsv4_e4m3fn_exp_scale[exp];
57	}
58	
59	static inline float dsv4_e4m3fn_dequant(float x) {
60	    const float sign = x < 0.0f ? -1.0f : 1.0f;
61	    const float ax = min(abs(x), 448.0f);
62	
63	    int lo = 0;
64	    int hi = 126;
65	    while (lo < hi) {
66	        const int mid = (lo + hi + 1) >> 1;
67	        if (dsv4_e4m3fn_value(mid) <= ax) {
68	            lo = mid;
69	        } else {
70	            hi = mid - 1;
71	        }
72	    }
73	
74	    int best = lo;
75	    if (best < 126) {
76	        const float best_diff = abs(ax - dsv4_e4m3fn_value(best));
77	        const float next_diff = abs(ax - dsv4_e4m3fn_value(best + 1));
78	        if (next_diff < best_diff || (next_diff == best_diff && ((best + 1) & 1) == 0 && (best & 1) != 0)) {
79	            best = best + 1;
80	        }
81	    }
82	
83	    return sign * dsv4_e4m3fn_value(best);
84	}
85	
86	static inline float dsv4_e2m1fn_dequant(float x) {
87	    const float sign = x < 0.0f ? -1.0f : 1.0f;
88	    const float ax = min(abs(x), 6.0f);
89	    int best = 0;
90	    float best_diff = abs(ax - dsv4_e2m1fn_values[0]);
91	    for (int i = 1; i < 8; i++) {
92	        const float diff = abs(ax - dsv4_e2m1fn_values[i]);
93	        if (diff < best_diff || (diff == best_diff && ((i & 1) == 0) && ((best & 1) != 0))) {
94	            best = i;
95	            best_diff = diff;
96	        }
97	    }
98	    return sign * dsv4_e2m1fn_values[best];
99	}
100	
101	// Quantizes the non-RoPE part of a KV row through E4M3FN and writes the
102	// dequantized value back as float. DS4 uses this to match the FP8 KV-cache
103	// semantics while keeping the Metal graph's cache buffers float-addressable.
104	kernel void kernel_dsv4_fp8_kv_quantize_f32(
105	        constant ds4_metal_args_dsv4_fp8_kv_quantize & args,
106	        device  const char * src0,
107	        device        char * dst,
108	        threadgroup  float * scratch [[threadgroup(0)]],
109	        uint row [[threadgroup_position_in_grid]],
110	        uint tid [[thread_position_in_threadgroup]]) {
111	    const int64_t n_rows = args.ne01 * args.ne02 * args.ne03;
112	    if ((int64_t) row >= n_rows) {
113	        return;
114	    }
115	
116	    const int64_t i1 = row % args.ne01;
117	    const int64_t i2 = (row / args.ne01) % args.ne02;
118	    const int64_t i3 = row / (args.ne01 * args.ne02);
119	
120	    device const char * src_base = src0 + i1*args.nb01 + i2*args.nb02 + i3*args.nb03;
121	    device       char * dst_base = dst  + i1*args.nb1  + i2*args.nb2  + i3*args.nb3;
122	
123	    const int64_t n_nope = args.ne00 - args.n_rot;
124	
125	    for (int64_t off = 0; off < n_nope; off += 64) {
126	        float v = 0.0f;
127	        if (tid < 64) {
128	            v = *((device const float *) (src_base + (off + tid)*args.nb00));
129	            scratch[tid] = abs(v);
130	        }
131	        threadgroup_barrier(mem_flags::mem_threadgroup);
132	
133	        for (uint stride = 32; stride > 0; stride >>= 1) {
134	            if (tid < stride) {
135	                scratch[tid] = max(scratch[tid], scratch[tid + stride]);
136	            }
137	            threadgroup_barrier(mem_flags::mem_threadgroup);
138	        }
139	
140	        const float amax = max(scratch[0], 1.0e-4f);
141	        const float scale = exp2(ceil(log2(amax / 448.0f)));
142	        if (tid < 64) {
143	            const float q = dsv4_e4m3fn_dequant(clamp(v / scale, -448.0f, 448.0f)) * scale;
144	            *((device float *) (dst_base + (off + tid)*args.nb0)) = q;
145	        }
146	        threadgroup_barrier(mem_flags::mem_threadgroup);
147	    }
148	
149	    for (int64_t i = n_nope + tid; i < args.ne00; i += 64) {
150	        *((device float *) (dst_base + i*args.nb0)) = *((device const float *) (src_base + i*args.nb00));
151	    }
152	}
153	
154	// The official DS4 indexer applies a 128-wide Hadamard rotation and then an
155	// inplace FP4 activation-simulation pass to both indexer Q and indexer KV.
156	kernel void kernel_dsv4_indexer_hadamard_fp4_f32(
157	        constant ds4_metal_args_dsv4_indexer_qat & args,
158	        device   char  * x,
159	        threadgroup float * scratch [[threadgroup(0)]],
160	        uint row [[threadgroup_position_in_grid]],
161	        uint tid [[thread_position_in_threadgroup]]) {
162	    if (row >= args.n_rows || args.head_dim != 128u || tid >= 128u) {
163	        return;
164	    }
165	
166	    threadgroup float *vals = scratch;
167	    threadgroup float *absbuf = scratch + 128;
168	    device float *xr = (device float *)(x + (uint64_t)row * args.row_stride);
169	
170	    vals[tid] = xr[tid];
171	    threadgroup_barrier(mem_flags::mem_threadgroup);
172	
173	    for (uint stride = 1u; stride < 128u; stride <<= 1u) {
174	        if ((tid & stride) == 0u) {
175	            const uint base = (tid & ~(2u * stride - 1u)) + (tid & (stride - 1u));
176	            const float a = vals[base];
177	            const float b = vals[base + stride];
178	            vals[base] = a + b;
179	            vals[base + stride] = a - b;
180	        }
181	        threadgroup_barrier(mem_flags::mem_threadgroup);
182	    }
183	
184	    float v = vals[tid] * 0.08838834764831845f;
185	    const uint block = tid >> 5u;
186	    const uint lane = tid & 31u;
187	    const uint block_base = block * 32u;
188	    absbuf[tid] = abs(v);
189	    threadgroup_barrier(mem_flags::mem_threadgroup);
190	
191	    for (uint stride = 16u; stride > 0u; stride >>= 1u) {
192	        if (lane < stride) {
193	            absbuf[block_base + lane] = max(absbuf[block_base + lane],
194	                                            absbuf[block_base + lane + stride]);
195	        }
