3039	static NSString *ds4_gpu_full_source(void) {
3040	    NSString *base = [NSString stringWithUTF8String:ds4_gpu_source];
3041	    NSFileManager *fm = [NSFileManager defaultManager];
3042	    /*
3043	     * Kernels are kept as separate files for review, then concatenated into one
3044	     * Metal library.  Environment overrides are still honored so a diagnostic
3045	     * run can swap one source file without changing the executable.
3046	     */
3047	    NSArray<NSArray<NSString *> *> *required_sources = @[
3048	        @[@"DS4_METAL_FLASH_ATTN_SOURCE", @"metal/flash_attn.metal"],
3049	        @[@"DS4_METAL_DENSE_SOURCE",      @"metal/dense.metal"],
3050	        @[@"DS4_METAL_MOE_SOURCE",        @"metal/moe.metal"],
3051	        @[@"DS4_METAL_DSV4_HC_SOURCE",    @"metal/dsv4_hc.metal"],
3052	        @[@"DS4_METAL_UNARY_SOURCE",      @"metal/unary.metal"],
3053	        @[@"DS4_METAL_DSV4_KV_SOURCE",    @"metal/dsv4_kv.metal"],
3054	        @[@"DS4_METAL_DSV4_ROPE_SOURCE",  @"metal/dsv4_rope.metal"],
3055	        @[@"DS4_METAL_DSV4_MISC_SOURCE",  @"metal/dsv4_misc.metal"],
3056	        @[@"DS4_METAL_ARGSORT_SOURCE",    @"metal/argsort.metal"],
3057	        @[@"DS4_METAL_CPY_SOURCE",        @"metal/cpy.metal"],
3058	        @[@"DS4_METAL_CONCAT_SOURCE",     @"metal/concat.metal"],
3059	        @[@"DS4_METAL_GET_ROWS_SOURCE",   @"metal/get_rows.metal"],
3060	        @[@"DS4_METAL_SUM_ROWS_SOURCE",   @"metal/sum_rows.metal"],
3061	        @[@"DS4_METAL_SOFTMAX_SOURCE",    @"metal/softmax.metal"],
3062	        @[@"DS4_METAL_REPEAT_SOURCE",     @"metal/repeat.metal"],
3063	        @[@"DS4_METAL_GLU_SOURCE",        @"metal/glu.metal"],
3064	        @[@"DS4_METAL_NORM_SOURCE",       @"metal/norm.metal"],
3065	        @[@"DS4_METAL_BIN_SOURCE",        @"metal/bin.metal"],
3066	        @[@"DS4_METAL_SET_ROWS_SOURCE",   @"metal/set_rows.metal"],
3067	    ];
3068	
3069	    NSMutableString *source = [NSMutableString stringWithString:base];
3070	    for (NSArray<NSString *> *spec in required_sources) {
3071	        const char *override_path = getenv([spec[0] UTF8String]);
3072	        NSMutableArray<NSString *> *paths = [NSMutableArray array];
3073	        if (override_path && override_path[0]) {
3074	            [paths addObject:[NSString stringWithUTF8String:override_path]];
3075	        }
3076	        [paths addObject:spec[1]];
3077	        [paths addObject:[@"./" stringByAppendingString:spec[1]]];
3078	
3079	        NSString *loaded = nil;
3080	        NSString *loaded_path = nil;
3081	        for (NSString *path in paths) {
3082	            if (![fm fileExistsAtPath:path]) continue;
3083	
3084	            NSError *error = nil;
3085	            loaded = [NSString stringWithContentsOfFile:path
3086	                                               encoding:NSUTF8StringEncoding
3087	                                                  error:&error];
3088	            if (!loaded) {
3089	                fprintf(stderr, "ds4: failed to read Metal source %s: %s\n",
3090	                        [path UTF8String], [[error localizedDescription] UTF8String]);
3091	                return nil;
3092	            }
